        .m_axi_arprot(cpu_axi4_32b_ar.prot),
        .m_axi_arqos(cpu_axi4_32b_ar.qos),
        .m_axi_arregion(cpu_axi4_32b_ar.region),
        .m_axi_aruser(cpu_axi4_32b_ar.user),
        .m_axi_arvalid(cpu_axi4_32b_arvalid),
        .m_axi_arready(cpu_axi4_32b_arready),
        .m_axi_rid(cpu_axi4_32b_r.id),
        .m_axi_rdata(cpu_axi4_32b_r.data),
        .m_axi_rresp(cpu_axi4_32b_r.resp),
        .m_axi_rlast(cpu_axi4_32b_r.last),
        .m_axi_ruser(cpu_axi4_32b_r.user),
        .m_axi_rvalid(cpu_axi4_32b_rvalid),
        .m_axi_rready(cpu_axi4_32b_rready)
    );

    // ================================================================
    // Direct passthrough: 64b → 64b (no converter)
    // Requests: fub_axi_* → cpu_axi4_64b_*
    // Responses: cpu_axi4_64b_* → MUX → fub_axi_*
    // ================================================================

    // AW channel (request: fub → output)
    assign cpu_axi4_64b_aw.id     = fub_axi_awid;
    assign cpu_axi4_64b_aw.addr   = fub_axi_awaddr;
    assign cpu_axi4_64b_aw.len    = fub_axi_awlen;
    assign cpu_axi4_64b_aw.size   = fub_axi_awsize;
    assign cpu_axi4_64b_aw.burst  = fub_axi_awburst;
    assign cpu_axi4_64b_aw.lock   = fub_axi_awlock;
    assign cpu_axi4_64b_aw.cache  = fub_axi_awcache;
    assign cpu_axi4_64b_aw.prot   = fub_axi_awprot;
    assign cpu_axi4_64b_aw.qos    = 4'b0;  // Tie to 0
    assign cpu_axi4_64b_aw.region = 4'b0;  // Tie to 0
    assign cpu_axi4_64b_aw.user   = 1'b0;  // Tie to 0
    assign cpu_axi4_64b_awvalid   = fub_axi_awvalid && aw_path_active_64b;
    // awready routed via MUX

    // W channel (request: fub → output)
    assign cpu_axi4_64b_w.data  = fub_axi_wdata;
    assign cpu_axi4_64b_w.strb  = fub_axi_wstrb;
    assign cpu_axi4_64b_w.last  = fub_axi_wlast;
    assign cpu_axi4_64b_w.user  = 1'b0;  // Tie to 0
    assign cpu_axi4_64b_wvalid  = fub_axi_wvalid && w_path_active_64b;
    // wready routed via MUX

    // B channel (response: output → MUX → fub)
    assign cpu_axi4_64b_bready = fub_axi_bready;
    // bid, bresp, bvalid routed via MUX (user field ignored)

    // AR channel (request: fub → output)
    assign cpu_axi4_64b_ar.id     = fub_axi_arid;
    assign cpu_axi4_64b_ar.addr   = fub_axi_araddr;
    assign cpu_axi4_64b_ar.len    = fub_axi_arlen;
    assign cpu_axi4_64b_ar.size   = fub_axi_arsize;
    assign cpu_axi4_64b_ar.burst  = fub_axi_arburst;
    assign cpu_axi4_64b_ar.lock   = fub_axi_arlock;
    assign cpu_axi4_64b_ar.cache  = fub_axi_arcache;
    assign cpu_axi4_64b_ar.prot   = fub_axi_arprot;
    assign cpu_axi4_64b_ar.qos    = 4'b0;  // Tie to 0
    assign cpu_axi4_64b_ar.region = 4'b0;  // Tie to 0
    assign cpu_axi4_64b_ar.user   = 1'b0;  // Tie to 0
    assign cpu_axi4_64b_arvalid   = fub_axi_arvalid && ar_path_active_64b;
    // arready routed via MUX

    // R channel (response: output → MUX → fub)
    assign cpu_axi4_64b_rready = fub_axi_rready;
    // rid, rdata, rresp, rlast, rvalid routed via MUX (user field ignored)

    // ================================================================
    // Response MUX - Route responses from width-specific paths
    // back to fub_axi_* based on address decode
    //
    // Request side (arready/awready/wready) uses the combinational
    // slave_select_{ar,aw} (valid while {ar,aw}valid is asserted).
    //
    // Response side (rvalid/rdata/..., bvalid/bid/...) cannot reuse
    // the combinational decode because fub_axi_{ar,aw}addr no longer
    // holds the request address once the {AR,AW} handshake completes
    // -- the decode reverts (typically to slave 0) and drops the
    // response. So we track slave_select_{ar,aw} per outstanding
    // request in a small FIFO captured at handshake, popped at
    // R-last / B; the FIFO head drives the response MUX.
    // ================================================================

    // OUTPUT slave_select_aw mirrors the live combinational decode.
    assign slave_select_aw = comb_slave_select_aw;

    // -------- AW->B slave_select tracking FIFO --------
    localparam int AW_TRK_DEPTH = 16;
    localparam int AW_TRK_AW    = 4;
    logic [NUM_SLAVES-1:0] aw_trk_mem [AW_TRK_DEPTH];
    logic [AW_TRK_AW:0] aw_trk_wptr, aw_trk_rptr;
    logic aw_trk_push, aw_trk_pop;

    assign aw_trk_push = fub_axi_awvalid && fub_axi_awready;
    assign aw_trk_pop  = fub_axi_bvalid && fub_axi_bready;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            aw_trk_wptr <= '0;
            aw_trk_rptr <= '0;
        end else begin
            if (aw_trk_push) begin
                aw_trk_mem[aw_trk_wptr[AW_TRK_AW-1:0]] <= comb_slave_select_aw;
                aw_trk_wptr <= aw_trk_wptr + 1'b1;
            end
            if (aw_trk_pop) begin
                aw_trk_rptr <= aw_trk_rptr + 1'b1;
            end
        end
    end

    assign b_slave_select = (aw_trk_wptr != aw_trk_rptr)
                          ? aw_trk_mem[aw_trk_rptr[AW_TRK_AW-1:0]]
                          : '0;

    // -------- AW->W slave_select tracking FIFO --------
    // Same push as AW (records slave_select at handshake);
    // pops on wlast so W#2's path-active gating doesn't wait
    // for B#1 to return. Without this, back-to-back writes
    // to different-width slaves stamp W#2's data on AW#1's
    // bucket (see multi-master 128b->32b/128b regression).
    logic [NUM_SLAVES-1:0] w_trk_mem [AW_TRK_DEPTH];
    logic [AW_TRK_AW:0] w_trk_wptr, w_trk_rptr;
    logic w_trk_push, w_trk_pop;

    assign w_trk_push = fub_axi_awvalid && fub_axi_awready;
    assign w_trk_pop  = fub_axi_wvalid && fub_axi_wready && fub_axi_wlast;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            w_trk_wptr <= '0;
            w_trk_rptr <= '0;
        end else begin
            if (w_trk_push) begin
                w_trk_mem[w_trk_wptr[AW_TRK_AW-1:0]] <= comb_slave_select_aw;
                w_trk_wptr <= w_trk_wptr + 1'b1;
            end
            if (w_trk_pop) begin
                w_trk_rptr <= w_trk_rptr + 1'b1;
            end
        end
    end

    assign w_slave_select = (w_trk_wptr != w_trk_rptr)
                          ? w_trk_mem[w_trk_rptr[AW_TRK_AW-1:0]]
                          : '0;

    // OUTPUT slave_select_ar mirrors the live combinational decode.
    assign slave_select_ar = comb_slave_select_ar;

    // -------- AR->R slave_select tracking FIFO --------
    localparam int AR_TRK_DEPTH = 16;
    localparam int AR_TRK_AW    = 4;
    logic [NUM_SLAVES-1:0] ar_trk_mem [AR_TRK_DEPTH];
    logic [AR_TRK_AW:0] ar_trk_wptr, ar_trk_rptr;
    logic ar_trk_push, ar_trk_pop;

    assign ar_trk_push = fub_axi_arvalid && fub_axi_arready;
    assign ar_trk_pop  = fub_axi_rvalid && fub_axi_rready && fub_axi_rlast;

    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            ar_trk_wptr <= '0;
            ar_trk_rptr <= '0;
        end else begin
            if (ar_trk_push) begin
                ar_trk_mem[ar_trk_wptr[AR_TRK_AW-1:0]] <= comb_slave_select_ar;
                ar_trk_wptr <= ar_trk_wptr + 1'b1;
            end
            if (ar_trk_pop) begin
                ar_trk_rptr <= ar_trk_rptr + 1'b1;
            end
        end
    end

    assign r_slave_select = (ar_trk_wptr != ar_trk_rptr)
                          ? ar_trk_mem[ar_trk_rptr[AR_TRK_AW-1:0]]
                          : '0;

    // AW-ready MUX (combinational comb_slave_select_aw — awaddr is live during awvalid)
    always_comb begin
        fub_axi_awready = 1'b0;
        case (comb_slave_select_aw)
            3'b010: begin  // Slave 1 (32b)
                fub_axi_awready = conv_32b_awready;
            end
            3'b100: begin  // Slave 2 (32b)
                fub_axi_awready = conv_32b_awready;
            end
            3'b001: begin  // Slave 0 (64b)
                fub_axi_awready = cpu_axi4_64b_awready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // W-ready MUX (FIFO-tracked w_slave_select — awaddr has already reverted by W phase)
    always_comb begin
        fub_axi_wready = 1'b0;
        case (w_slave_select)
            3'b010: begin  // Slave 1 (32b)
                fub_axi_wready = conv_32b_wready;
            end
            3'b100: begin  // Slave 2 (32b)
                fub_axi_wready = conv_32b_wready;
            end
            3'b001: begin  // Slave 0 (64b)
                fub_axi_wready = cpu_axi4_64b_wready;
            end
            default: begin
                // No active W transaction
            end
        endcase
    end

    // Write response MUX (B channel - uses b_slave_select FIFO head)
    always_comb begin
        fub_axi_bid = 4'd0;
        fub_axi_bresp = 2'b00;
        fub_axi_bvalid = 1'b0;

        case (b_slave_select)
            3'b010: begin  // Slave 1 (32b)
                fub_axi_bid = conv_32b_bid;
                fub_axi_bresp = conv_32b_bresp;
                fub_axi_bvalid = conv_32b_bvalid;
            end
            3'b100: begin  // Slave 2 (32b)
                fub_axi_bid = conv_32b_bid;
                fub_axi_bresp = conv_32b_bresp;
                fub_axi_bvalid = conv_32b_bvalid;
            end
            3'b001: begin  // Slave 0 (64b)
                fub_axi_bid = cpu_axi4_64b_b.id;
                fub_axi_bresp = cpu_axi4_64b_b.resp;
                fub_axi_bvalid = cpu_axi4_64b_bvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

    // AR-ready MUX (request side: uses combinational comb_slave_select_ar)
    always_comb begin
        fub_axi_arready = 1'b0;
        case (comb_slave_select_ar)
            3'b010: begin  // Slave 1 (32b)
                fub_axi_arready = conv_32b_arready;
            end
            3'b100: begin  // Slave 2 (32b)
                fub_axi_arready = conv_32b_arready;
            end
            3'b001: begin  // Slave 0 (64b)
                fub_axi_arready = cpu_axi4_64b_arready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // Read response MUX (R channel - uses r_slave_select FIFO head)
    always_comb begin
        fub_axi_rid = 4'd0;
        fub_axi_rdata = 64'd0;
        fub_axi_rresp = 2'b00;
        fub_axi_rlast = 1'b0;
        fub_axi_rvalid = 1'b0;

        case (r_slave_select)
            3'b010: begin  // Slave 1 (32b)
                fub_axi_rid = conv_32b_rid;
                fub_axi_rdata = conv_32b_rdata;
                fub_axi_rresp = conv_32b_rresp;
                fub_axi_rlast = conv_32b_rlast;
                fub_axi_rvalid = conv_32b_rvalid;
            end
            3'b100: begin  // Slave 2 (32b)
                fub_axi_rid = conv_32b_rid;
                fub_axi_rdata = conv_32b_rdata;
                fub_axi_rresp = conv_32b_rresp;
                fub_axi_rlast = conv_32b_rlast;
                fub_axi_rvalid = conv_32b_rvalid;
            end
            3'b001: begin  // Slave 0 (64b)
                fub_axi_rid = cpu_axi4_64b_r.id;
                fub_axi_rdata = cpu_axi4_64b_r.data;
                fub_axi_rresp = cpu_axi4_64b_r.resp;
                fub_axi_rlast = cpu_axi4_64b_r.last;
                fub_axi_rvalid = cpu_axi4_64b_rvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

endmodule : cpu_axi4_adapter
